const body = $input.first().json.body || $input.first().json;
const description = (body.description || '').trim();
const channelId   = body.channelId || '';
const userId      = body.userId || '';
const userName    = body.userName || 'user';
// Sanitize jobId: only 8 lowercase hex chars
const jobId      = (body.jobId || '').toString().replace(/[^a-f0-9]/gi, '').slice(0, 8).toLowerCase();
const inlineCode = (body.inlineCode || '').trim();

if (!description) {
  throw new Error('description is required');
}

return [{ json: { description, channelId, userId, userName, jobId, inlineCode } }];

const d = $input.first().json;

const code        = d.code || '';
const description = d.description || '';
const channelId   = d.channelId || '';
const userId      = d.userId || '';
const userName    = d.userName || 'user';
const success     = d.success || false;
const jobId       = d.job_id || '';
const stlPath     = d.stl_path || null;
const pngB64      = d.png_b64 || null;
const attempts    = d.attempts || 1;
const error       = d.error || null;

return [{ json: { code, description, channelId, userId, userName, success, jobId, stlPath, pngB64, attempts, error } }];

const prev = $input.first().json;
const pngB64 = prev.pngB64 || null;

// Build binary item from base64 if we have a PNG
const result = { json: prev };
if (pngB64) {
  result.binary = {
    data: {
      data: pngB64,
      mimeType: 'image/png',
      fileName: '3d-preview.png',
      fileSize: Math.ceil(pngB64.length * 0.75),
    }
  };
}
return [result];

