={{ (() => {
  const d = $input.first().json;
  const channelId   = d.channelId || '';
  const description = d.description || '';
  const stlPath     = d.stlPath || null;
  const code        = d.code || '';
  const jobId       = d.jobId || '';
  const success     = d.success !== false;
  const attempts    = d.attempts || 1;
  const error       = d.error || null;
  const imageUrl = jobId ? 'https://appendicular-wilson-looser.ngrok-free.dev/webhook/preview-3d?job=' + jobId : null;

  // Truncate code for Slack block (3000 char limit per block)
  const codePath = stlPath ? stlPath.replace(/\.stl$/, '.py') : null;
  const codeSnip = code.length > 2600
    ? code.slice(0, 2600) + '\n# ... (full code saved at ' + (codePath || 'server') + ')'
    : code;

  const blocks = [
    { type: 'header', text: { type: 'plain_text', text: ':triangular_ruler: 3D Model Generated', emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*' + description + '*' } },
  ];

  if (imageUrl) {
    blocks.push({ type: 'image', image_url: imageUrl, alt_text: '3D model preview' });
  }

  blocks.push({ type: 'divider' });

  if (stlPath) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn',
      text: ':white_check_mark: *STL:* `' + stlPath + '`\n_Slice in PrusaSlicer / Bambu Studio / Cura to print_' } });
  }

  if (!success || error) {
    const errMsg = error ? error.slice(0, 300) : 'Model generation had issues — check the code manually.';
    blocks.push({ type: 'section', text: { type: 'mrkdwn',
      text: ':warning: *Generation issue:* ' + errMsg } });
  } else if (attempts > 1) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn',
      text: ':repeat: _Self-corrected in ' + attempts + ' attempt' + (attempts > 1 ? 's' : '') + '_' } });
  }

  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*CadQuery source:*\n```\n' + codeSnip + '\n```' } });

  const hint = jobId
    ? ':pencil: Paste into CadQuery / Python to edit · _Job: `' + jobId + '` · Improve with `/3d improve ' + jobId + ' <changes>`_'
    : ':pencil: Paste code into CadQuery / Python to edit · _Improve with `/3d code <description>\\n<paste code>`_';
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: hint }] });

  return JSON.stringify({ channel: channelId, blocks, unfurl_links: false });
})() }}

