const https = require('https');

function httpsReq(options, body) {
  return new Promise((resolve, reject) => {
    if (Buffer.isBuffer(body)) {
      options.headers = options.headers || {};
      options.headers['Content-Length'] = body.length;
    }
    const req = https.request(options, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(text)); } catch { resolve({ _raw: text }); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const token = $env.SLACK_BOT_TOKEN;
const item = $input.first();
const b64 = item.binary && item.binary.data ? item.binary.data.data : null;

if (!b64) {
  return [{ json: { ...item.json, fileId: null, uploaded: false } }];
}

const buf = Buffer.from(b64, 'base64');
const mimeType = item.binary.data.mimeType || 'application/octet-stream';
const fileName = item.binary.data.fileName || 'file.bin';
const channelId = item.json.channelId || '';
const description = item.json.description || '';
const stlPath = item.json.stlPath || null;

// Step 0: Join the channel so the bot can share files there
// (chat.postMessage works without joining, but files.completeUploadExternal requires membership)
if (channelId) {
  const joinBody = `channel=${encodeURIComponent(channelId)}`;
  await httpsReq({
    method: 'POST', hostname: 'slack.com',
    path: '/api/conversations.join',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/x-www-form-urlencoded',
      'Content-Length': Buffer.byteLength(joinBody),
    }
  }, Buffer.from(joinBody));
  // Ignore join errors (may already be a member, or private channel)
}

// Step 1: Get upload URL
const body1 = `filename=${encodeURIComponent(fileName)}&length=${buf.length}`;
const urlData = await httpsReq({
  method: 'POST', hostname: 'slack.com',
  path: '/api/files.getUploadURLExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/x-www-form-urlencoded',
    'Content-Length': Buffer.byteLength(body1),
  }
}, Buffer.from(body1));

if (!urlData.ok) throw new Error(`getUploadURL failed: ${JSON.stringify(urlData)}`);
const { upload_url, file_id } = urlData;

// Step 2: PUT binary
const urlMatch = upload_url.match(/^https?:\/\/([^\/]+)(\/[^?]*)?(\?.*)?$/);
await httpsReq({
  method: 'PUT', hostname: urlMatch[1],
  path: (urlMatch[2] || '/') + (urlMatch[3] || ''),
  headers: { 'Content-Type': mimeType, 'Content-Length': buf.length }
}, buf);

// Step 3: Complete + share to channel — now that bot has joined, this should work
const comment = `:triangular_ruler: *3D Preview* — ${description}`
  + (stlPath ? `\n:white_check_mark: STL: \`${stlPath}\`\n_Open in PrusaSlicer, Bambu Studio, or OpenSCAD_` : '');

const completeBody = JSON.stringify({
  files: [{ id: file_id }],
  ...(channelId ? { channel_id: channelId } : {}),
  initial_comment: comment,
});

const completeResp = await httpsReq({
  method: 'POST', hostname: 'slack.com',
  path: '/api/files.completeUploadExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(completeBody),
  }
}, Buffer.from(completeBody));

const fileShared = completeResp.ok || false;
const fileError = completeResp.error || null;

return [{ json: {
  ...item.json,
  fileId: file_id,
  uploaded: true,
  fileShared,
  fileError,
} }];
